C++<pre><code>#include &lt;cstdio&gt;
#include &lt;vector&gt;
#include &lt;algorithm&gt;

long long search(std::vector&lt;int&gt; &amp;vec, int height, int H)
{
    long long min = 0, max = vec.size() - 1;
    long long i = 0;
    for (i = 0; i &lt; vec.size(); i++)
    {
        if (vec[i] &gt;= height - H)
        {
            break;
        }
    }
    min = i;
    for (i = vec.size() - 1; i &gt;= 0; i--)
    {
        if (vec[i] - H &lt;= height)
        {
            break;
        }
    }
    max = i;
    return max - min + 1;
}

int main(int argc, const char* argv[])
{
    int M, K, H;
    long long count = 0;
    scanf("%d%d%d", &amp;M, &amp;K, &amp;H);
    if (K &lt; M - 1)
    {
        std::vector&lt;int&gt; stair;
        int height = 0;
        std::vector&lt;int&gt; dele(M - K, 0);
        for (int i = 0; i &lt; M; i++)
        {
            scanf("%d", &amp;height);
            count += search(stair, height, H);
            if (i &lt; M - K)
            {
                dele[i] = height;
            }
            if (i &gt;= K)
            {
                // 先删除一个元素
                stair.erase(remove(stair.begin(), stair.end(), dele[i - K]), stair.end());
            }
            // 二分插入新的元素
            int left = 0, right = stair.size() - 1;
            int mid;
            while (left &lt;= right)
            {
                mid = left + (right - left) / 2;
                if (height &lt; stair[mid])
                {
                    right = mid - 1;
                }
                else
                {
                    left = mid + 1;
                }
            }
            stair.insert(stair.begin() + left, height);
        }
    }
    else
    {
        // K&gt;=M-1，全区间都可能跳跃
        std::vector&lt;int&gt; stair;
        int height = 0;
        for (int i = 0; i &lt; M; i++)
        {
            scanf("%d", &amp;height);
            count += search(stair, height, H);
            //  二分插入新的元素
            int left = 0, right = stair.size() - 1;
            int mid;
            while (left &lt;= right)
            {
                mid = left + (right - left) / 2;
                if (height &lt; stair[mid])
                {
                    right = mid - 1;
                }
                else
                {
                    left = mid + 1;
                }
            }
            stair.insert(stair.begin() + left, height);
        }
    }
    printf("%lld", count);
    return 0;
}
